INSERT OR IGNORE INTO comment (_id, uid, nick, mail, mailMd5, link, ua, ip, master, url, href, comment, pid, rid, isSpam, created, updated, like, top, avatar) VALUES ('238', '', '金色河流', '534500549@qq.com', 'c9705dc5e8248a952c30cbb286324abe', 'https://goldenriver.site', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36', '206.237.119.229', 0, '/archives/jiapingwachenmo.html', '', '“抄袭打假”这件事我也围观好久了，就披露出来的材料分析，抄袭都是确有其事。之前是出版作品，但是大多都没有得到当事人和涉事方的回应。我感觉文学圈好像自成生态，包括进作协、发期刊、搞教职，一直不太受大众市场的影响。这次有打假博主掀开遮羞布，才发现这么有多蟑螂。

这次爆出来的贾浅浅的学术论文抄袭问题，我看到校方已启动调查程序，算是撬动了比较实的一方。如果严重的话可能会对贾浅浅在西北大学的教职有影响。
最终结果也不好说，但是这类的调查和处罚是会考虑舆论影响的。如果大众都不关注这件事了，相关单位会选择考虑轻拿轻放，息事宁人。特别考虑到贾平凹是作协主席，考虑到体系里利益关系，最有可能的结果就是当事人自罚三杯就结束了。

我不知道截图的这个人立场站在哪，看起来自作聪明，确实从当事人危机公关的角度来说，先缩头等舆论过去，通常是自身利益减损最小的一种做法。毕竟文学圈还是小圈子，作为一个破圈的新闻来说，大众视野可能今天为它停留，明天就忘记这件事了。我猜测，现在的当事人应该忙着走关系让调查方轻拿轻放，忙着自查作品和身迹以免再惹是非。

但是我一直在想，这一类事为什么值得关注。“让子弹飞”，是对那些既不了解其中是非曲直，又不看热闹嫌事大的“好事者”来说的。
但就我的观察和了解，这类抄袭事件触动了普通人对公平、创作、尊严和底线的共同直觉。如果是对于文学还有关注，还有的基本道德直觉，就应该在保持理智的前提下，在舆论监督这一端的天平上加码。

', '', '', 0, 1775712518000, 1775712518000, '[]', 0, 'https://cravatar.cn/avatar/c9705dc5e8248a952c30cbb286324abe?d=mp');
