INSERT OR IGNORE INTO comment (_id, uid, nick, mail, mailMd5, link, ua, ip, master, url, href, comment, pid, rid, isSpam, created, updated, like, top, avatar) VALUES ('255', '', '金色河流', '534500549@qq.com', 'c9705dc5e8248a952c30cbb286324abe', 'https://goldenriver.site', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36', '223.104.67.180', 0, '/archives/wangkuishanouran.html', '', '看了一下，是06年的小说，印象里那个时代很多这一类讽刺官场作风或者社会风气的作品。
我想起了朱文有个短篇叫《人民到底需不需要桑拿》，也是零几年写的，讲的也是个退休老头，闲着无聊，对于大街小巷冒出来的桑拿店看不惯，煞有介事地一通研究，最后写信给报纸，发起一个“人民到底需不需要桑拿”大讨论。有点黑色幽默，有点荒诞。
现在这类作品都很少了。', '', '', 0, 1775972463000, 1775972463000, '[]', 0, 'https://cravatar.cn/avatar/c9705dc5e8248a952c30cbb286324abe?d=mp');
