INSERT OR IGNORE INTO comment (_id, uid, nick, mail, mailMd5, link, ua, ip, master, url, href, comment, pid, rid, isSpam, created, updated, like, top, avatar) VALUES ('271', '', '合荒', '1010289577@qq.com', '21cf50dfa55323e425026604a81e39c6', '', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36 Edg/146.0.0.0', '45.149.92.90', 0, '/archives/wulihuashiyan.html', '', '主要是各方面都怕担责任：我们年级有个同学高一时候生物实验玩过氧化氢把手漂白了，还有探究金属钠的性质把钠给偷走的……主要是这还是全市重点学校中的重点学校啊，
其次是这东西是个悖论：因为你实验操作不正确，不敢让你接触实验，你不接触实验，还不能正确操作实验。就一个简单的从胶头滴管取溶液滴入试管中（好吧，其实不简单，我也手抖），几乎就没有手不抖的', '', '', 0, 1776222049000, 1776222049000, '[]', 0, 'https://cravatar.cn/avatar/21cf50dfa55323e425026604a81e39c6?d=mp');
